HEADER

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
CURRENT_USER="${USER:-$(id -un)}"
USER_HOME="${HOME:-/home/${CURRENT_USER}}"
ANDROID_TOOLCHAIN="${ANDROID_TOOLCHAIN:-${USER_HOME}/Android/NDK/build/cmake/android.toolchain.cmake}"
ANDROID_PLATFORM="android-35"
BUILD_TYPE="Release"
BUILD_DIR="${SCRIPT_DIR}/build"
MAGISK_DIR="${SCRIPT_DIR}/apm-magisk"
MAGISK_FILES_DIR="${MAGISK_DIR}/files"
DIST_DIR="${SCRIPT_DIR}/dist"

CHOICES=(
    "arm64-v8a|ARM64 (arm64-v8a)|arm64-v8a|"
    "armeabi-v7a|ARMv7 (armeabi-v7a)|armeabi-v7a|"
    "armeabi|ARM (armeabi) (DEPRECATED)|armeabi|"
    "armeabi-v7a-neon|ARMv7 (Hard-Float + NEON)|armeabi-v7a|-DANDROID_ARM_NEON=ON"
    "x86|x86 (Modern emulators)|x86|"
    "x86_64|x86_64 (Modern emulators)|x86_64|"
    "arm64-v8a-static|ARM64 (arm64-v8a) (Static Linking)|arm64-v8a|-DANDROID_STL=c++_static"
)

TARGET_SLUG=""
TARGET_LABEL=""
TARGET_ABI=""
TARGET_EXTRA=""

prompt_architecture() {
    echo "Select the architecture you would like to build for:"
    local idx=0
    for entry in "${CHOICES[@]}"; do
        IFS="|" read -r slug label _abi _extra <<<"${entry}"
        printf "  %d) %s\n" "$((idx + 1))" "${label}"
        idx=$((idx + 1))
    done

    local selection
    while true; do
        read -rp "Enter a number [1-${#CHOICES[@]}]: " selection
        if [[ "${selection}" =~ ^[0-9]+$ ]]; then
            local choice_index=$((selection - 1))
            if (( choice_index >= 0 && choice_index < ${#CHOICES[@]} )); then
                local slug label abi extra
                IFS="|" read -r slug label abi extra <<<"${CHOICES[$choice_index]}"
                TARGET_SLUG="${slug}"
                TARGET_LABEL="${label}"
                TARGET_ABI="${abi}"
                TARGET_EXTRA="${extra}"
                echo
                echo "Preparing to compile APM for ${TARGET_LABEL}."
                return
            fi
        fi
        echo "Invalid selection. Please try again."
    done
}

detect_jobs() {
    if command -v nproc >/dev/null 2>&1; then
        nproc
    elif command -v sysctl >/dev/null 2>&1; then
        sysctl -n hw.ncpu
    else
        echo 4
    fi
}

configure_project() {
    mkdir -p "${BUILD_DIR}"

    local cmake_args=(
        -S "${SCRIPT_DIR}"
        -B "${BUILD_DIR}"
        -DCMAKE_TOOLCHAIN_FILE="${ANDROID_TOOLCHAIN}"
        -DANDROID_ABI="${TARGET_ABI}"
        -DANDROID_PLATFORM="${ANDROID_PLATFORM}"
        -DCMAKE_BUILD_TYPE="${BUILD_TYPE}"
    )

    if [[ -n "${TARGET_EXTRA}" ]]; then
        cmake_args+=("${TARGET_EXTRA}")
    fi

    echo "Configuring CMake with Android ABI ${TARGET_ABI}..."
    cmake "${cmake_args[@]}"
}

build_project() {
    local jobs
    jobs="$(detect_jobs)"
    for pass in 1 2; do
        echo "Starting build pass ${pass}/2 (mirrors 'make -j\$(nproc)' from the manual steps)..."
        cmake --build "${BUILD_DIR}" -- -j"${jobs}"
    done
    echo "Build complete for ${TARGET_LABEL}."
}

copy_binary_into_module() {
    local source_binary="$1"
    local destination_name="$2"

    if [[ ! -f "${source_binary}" ]]; then
        echo "Error: ${source_binary} not found. Make sure the build completed successfully." >&2
        exit 1
    fi

    mkdir -p "${MAGISK_FILES_DIR}"
    cp -f "${source_binary}" "${MAGISK_FILES_DIR}/${destination_name}"
    chmod 755 "${MAGISK_FILES_DIR}/${destination_name}"
}

stage_magisk_template() {
    if ! command -v base64 >/dev/null 2>&1; then
        echo "Error: 'base64' command not found. Install coreutils/base64 to package the Magisk module." >&2
        exit 1
    fi

    if ! command -v tar >/dev/null 2>&1; then
        echo "Error: 'tar' command not found. Install tar to package the Magisk module." >&2
        exit 1
    fi

    rm -rf "${MAGISK_DIR}"
    mkdir -p "${MAGISK_DIR}"

