MAGISK_TEMPLATE_ARCHIVE

    tar -C "${MAGISK_DIR}" -xzf "${tmp_archive}"
    rm -f "${tmp_archive}"

    rm -f "${MAGISK_FILES_DIR}/apm" "${MAGISK_FILES_DIR}/apmd"
}

package_magisk_module() {
    stage_magisk_template

    copy_binary_into_module "${BUILD_DIR}/apm" "apm"
    copy_binary_into_module "${BUILD_DIR}/apmd" "apmd"

    if ! command -v zip >/dev/null 2>&1; then
        echo "Error: 'zip' command not found. Please install it to package the module." >&2
        exit 1
    fi

    mkdir -p "${DIST_DIR}"
    local timestamp
    timestamp="$(date +%Y%m%d-%H%M%S)"
    local output_zip
    output_zip="${DIST_DIR}/apm-magisk-${TARGET_SLUG}-${timestamp}.zip"

    echo "Creating Magisk module ZIP at ${output_zip}..."
    (
        cd "${MAGISK_DIR}" >/dev/null 2>&1
        zip -qr "${output_zip}" .
    )

    echo "Magisk module packaged successfully: ${output_zip}"
}

prompt_magisk_packaging() {
    local response
    while true; do
        read -rp "Would you like to package the Magisk module now? [y/N]: " response
        case "${response}" in
            [yY]|[yY][eE][sS])
                package_magisk_module
                return
                ;;
            ""|[nN]|[nN][oO])
                echo "Skipping Magisk module packaging."
                return
                ;;
            *)
                echo "Please answer 'y' or 'n'."
                ;;
        esac
    done
}

main() {
    prompt_architecture
    configure_project
    build_project
    prompt_magisk_packaging
}

main "$@"
